), inserted_matches as (
  insert into public.matches (play_date_id, played_at, score1, score2, submitted_via, source, status, validation_notes)
  select
    pd.id,
    import_rows.played_at,
    import_rows.score1,
    import_rows.score2,
    'historical-import',
    'historical-import',
    'validated',
